const allBrandMap = { ...simpleBrandMap, ...customBrandMap };

export function applyBrandIcons(root = document) {
  const elements = root.querySelectorAll("[data-brand]");
  elements.forEach((el) => {
    const brand = el.getAttribute("data-brand");
    const icon = allBrandMap[brand];
    if (!icon) return;
    el.innerHTML = `<svg role="img" viewBox="0 0 24 24" width="1em" height="1em" aria-label="${icon.title}" xmlns="http://www.w3.org/2000/svg"><path fill="#${icon.hex}" d="${icon.path}"/></svg>`;
  });
}
